using System;
using System.IO;
using System.Linq;
using System.Reflection;
using System.Runtime.InteropServices;

var home = Environment.GetFolderPath(Environment.SpecialFolder.UserProfile);
var corePath = Path.Combine(home, ".nuget/packages/xunit.v3.extensibility.core/3.2.2/lib/netstandard2.0/xunit.v3.core.dll");
var commonPath = Path.Combine(home, ".nuget/packages/xunit.v3.common/3.2.2/lib/netstandard2.0/xunit.v3.common.dll");

var runtimeDir = RuntimeEnvironment.GetRuntimeDirectory();
var resolver = new PathAssemblyResolver(
    Directory.GetFiles(runtimeDir, "*.dll")
        .Append(corePath)
        .Append(commonPath));
using var mlc = new MetadataLoadContext(resolver);
var asm = mlc.LoadFromAssemblyPath(corePath);

// Check TestCaseOrdererAttribute constructors
var tca = asm.GetType("Xunit.TestCaseOrdererAttribute");
Console.WriteLine("=== TestCaseOrdererAttribute ===");
foreach (var ctor in tca.GetConstructors())
{
    var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
    Console.WriteLine($"  ctor({parms})");
}

// Check CollectionBehaviorAttribute constructors
var cba = asm.GetType("Xunit.CollectionBehaviorAttribute");
Console.WriteLine("\n=== CollectionBehaviorAttribute ===");
foreach (var ctor in cba.GetConstructors())
{
    var parms = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
    Console.WriteLine($"  ctor({parms})");
}

// Check ICollectionBehaviorAttribute
var icba = asm.GetType("Xunit.v3.ICollectionBehaviorAttribute");
Console.WriteLine("\n=== ICollectionBehaviorAttribute ===");
if (icba != null)
{
    foreach (var m in icba.GetMembers())
        Console.WriteLine($"  {m.MemberType}: {m.Name}");
}

// Check ITestCaseOrdererAttribute
var itca = asm.GetType("Xunit.v3.ITestCaseOrdererAttribute");
Console.WriteLine("\n=== ITestCaseOrdererAttribute ===");
if (itca != null)
{
    foreach (var m in itca.GetMembers())
        Console.WriteLine($"  {m.MemberType}: {m.Name}");
}
